package github.chains;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ParseResult;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.AnnotationExpr;
import com.github.javaparser.ast.expr.MemberValuePair;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.IntegerLiteralExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import com.github.javaparser.ast.NodeList;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.HashMap;
import java.util.Map;

public class Main {

    private static final Map<String, Integer> TV_CONSTANTS = new HashMap<>();

    static {
        TV_CONSTANTS.put("SEVEN", 7);
        TV_CONSTANTS.put("TEN", 10);
        TV_CONSTANTS.put("MILLION", 1000000);
    }

    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-file-or-directory>");
            System.exit(1);
        }

        String path = args[0];
        File file = new File(path);

        if (file.isDirectory()) {
            for (File f : file.listFiles((dir, name) -> name.endsWith(".java"))) {
                processFile(f);
            }
        } else {
            processFile(file);
        }

        System.out.println("Transformation completed successfully.");
    }

    private static void processFile(File file) throws Exception {
        System.out.println("Processing: " + file.getAbsolutePath());

        String content = Files.readString(file.toPath());
        JavaParser parser = new JavaParser();
        ParseResult<CompilationUnit> result = parser.parse(content);

        if (!result.isSuccessful() || result.getResult().isEmpty()) {
            System.err.println("Failed to parse: " + file.getAbsolutePath());
            result.getProblems().forEach(p -> System.err.println(p.getMessage()));
            return;
        }

        CompilationUnit cu = result.getResult().get();

        cu.getImports().removeIf(
            importDecl -> "com.jcabi.aspects.Tv".equals(importDecl.getNameAsString())
        );

        TvReplacementVisitor visitor = new TvReplacementVisitor();
        visitor.visit(cu, null);

        Files.writeString(file.toPath(), cu.toString());
        System.out.println("  Fixed: " + file.getAbsolutePath());
    }

    private static class TvReplacementVisitor extends VoidVisitorAdapter<Void> {

        @Override
        public void visit(AnnotationExpr node, Void arg) {
            super.visit(node, arg);

            NodeList<MemberValuePair> pairs = node.asNormalAnnotationExpr().getPairs();
            NodeList<MemberValuePair> toRemove = new NodeList<>();

            for (MemberValuePair pair : pairs) {
                Expression value = pair.getValue();
                if (value instanceof NameExpr) {
                    NameExpr nameExpr = (NameExpr) value;
                    String name = nameExpr.getNameAsString();
                    if (name.startsWith("Tv.")) {
                        String constant = name.substring(3);
                        if (TV_CONSTANTS.containsKey(constant)) {
                            IntegerLiteralExpr literal = new IntegerLiteralExpr(
                                String.valueOf(TV_CONSTANTS.get(constant))
                            );
                            pair.setValue(literal);
                        }
                    }
                }
            }
        }

        @Override
        public void visit(NameExpr node, Void arg) {
            super.visit(node, arg);

            String name = node.getNameAsString();
            if (name.startsWith("Tv.")) {
                String constant = name.substring(3);
                if (TV_CONSTANTS.containsKey(constant)) {
                    IntegerLiteralExpr literal = new IntegerLiteralExpr(
                        String.valueOf(TV_CONSTANTS.get(constant))
                    );
                    node.replace(literal);
                }
            }
        }
    }
}

package github.chains;

import com.github.javaparser.JavaParser;
